const request = $json.body ?? $json;
const headers = $json.headers ?? {};
const expectedSecret = String($env.N8N_AI_TEST_WEBHOOK_SECRET || '').trim();
const incomingSecret = String(headers['x-quicreply-webhook-secret'] || headers['X-Quicreply-Webhook-Secret'] || '').trim();
const context = request.businessContext || {};
const knowledge = request.aiKnowledge || {};

if (!expectedSecret || incomingSecret !== expectedSecret) {
  throw new Error('Unauthorized AI test webhook request.');
}
if (request.contextQuality?.isReady !== true || !String(context.businessDescription || '').trim() || !String(context.productsServices || '').trim()) {
  return [{ json: { guardMessage: 'Complete Jennifer setup before testing.' } }];
}

const history = Array.isArray(request.conversationHistory) ? request.conversationHistory.slice(-6) : [];
const prompt = [
  'You are Jennifer, the QuicReply AI assistant in a test environment.',
  'Answer as a concise storefront assistant using only the supplied business facts.',
  'Never claim you sent a message, changed an order, issued a refund, updated an account, or completed another live action.',
  'Do not invent prices, stock, policies, delivery times, or product details.',
  'Answer directly and ask at most one follow-up question.',
  `Business: ${String(context.businessDescription || '')}`,
  `Products and services: ${String(context.productsServices || '')}`,
  `Pricing and plans: ${String(knowledge.pricingAndPlans || 'Not provided.')}`,
  `Seats and limits: ${String(knowledge.seatsAndLimits || 'Not provided.')}`,
  `Core features: ${String(knowledge.coreFeatures || 'Not provided.')}`,
  `Product pages: ${String(knowledge.productPages || 'Not provided.')}`,
  `Policies and FAQs: ${String(knowledge.policiesAndFaqs || 'Not provided.')}`,
  `Response style: ${String(context.responseStyle || 'professional')}`,
  `Language: ${String(context.aiLanguage || 'English')}`,
  `Conversation: ${history.map((entry) => `${entry.role || 'user'}: ${String(entry.text || '').trim()}`).join('\n') || 'No prior conversation.'}`,
  `Customer message: ${String(request.prompt || '').trim()}`,
  'Return plain answer text only.'
].join('\n');

return [{ json: { guardMessage: '', openclawPrompt: prompt } }];

if ($json.guardMessage) {
  return [{ json: { message: $json.guardMessage, route: 'n8n.guard', warnings: [] } }];
}
if ($json.error) {
  return [{ json: { message: 'Jennifer runtime could not be reached.', route: 'openclaw.ai-test', warnings: ['runtime_unreachable'] } }];
}
const output = Array.isArray($json.output) ? $json.output : [];
const text = output.flatMap((entry) => Array.isArray(entry.content) ? entry.content : []).find((entry) => entry?.type === 'output_text' && typeof entry.text === 'string')?.text?.trim();
if (!text || text.startsWith('```') || text.includes('<tool')) {
  return [{ json: { message: 'Jennifer runtime failed to produce a response.', route: 'openclaw.ai-test', warnings: ['runtime_invalid_output'] } }];
}
return [{ json: { message: text, route: 'openclaw.ai-test', warnings: [] } }];
